+  if (!node) {
+    return NULL;
+  }
+
+  size_t count = 0;
+  rcl_ret_t ret = count_function(node, topic_name, &count);
+  if (ret != RCL_RET_OK) {
+    PyErr_Format(PyExc_RuntimeError, "Failed to count %s: %s",
+      type, rcl_get_error_string_safe());
+    rcl_reset_error();
+    return NULL;
+  }
+
+  return PyLong_FromSize_t(count);
